function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function districtNumber(district) {
  const raw = clean(district).toUpperCase();
  const match = raw.match(/D?(\d{1,2})/);
  if (!match) return null;
  const num = Number(match[1]);
  if (!Number.isFinite(num) || num < 1 || num > 28) return null;
  return num;
}

function uraBatchFromDistrict(district) {
  const num = districtNumber(district);
  if (!num) return '';
  if (num >= 1 && num <= 7) return '1';
  if (num >= 8 && num <= 14) return '2';
  if (num >= 15 && num <= 21) return '3';
  if (num >= 22 && num <= 28) return '4';
  return '';
}

function shouldUpdate(currentBatch, correctBatch) {
  const current = clean(currentBatch);
  if (!correctBatch) return false;
  if (!current) return true;
  if (current !== correctBatch) return true;
  return false;
}

const output = [];

for (const item of items) {
  const row = item.json;

  const sourceKey = clean(row['Source Key']);
  const propertyRecordId = clean(row['Property Record ID']);
  const district = clean(row['District']);
  const currentBatch = clean(row['URA Batch']);
  const correctBatch = uraBatchFromDistrict(district);

  if (!sourceKey) continue;
  if (!district) continue;
  if (!correctBatch) continue;
  if (!shouldUpdate(currentBatch, correctBatch)) continue;

  output.push({
    json: {
      'Source Key': sourceKey,
      'Property Record ID': propertyRecordId,
      'District': district,
      'URA Batch': correctBatch,
    },
  });
}

return output;
